class Solution:
    def calculateScore(self, instructions, values):
        n = len(instructions)
        i = 0
        score = 0
        visited = set()
        while 0 <= i < n and i not in visited:
            visited.add(i)
            if instructions[i] == 'add':
                score += values[i]
                i += 1
            else:
                i += values[i]
        return score

