class Solution:
    def calculateScore(self, instructions, values):
        n = len(instructions)
        seen = [False] * n
        i = 0
        score = 0
        while 0 <= i < n and not seen[i]:
            seen[i] = True
            if instructions[i] == 'add':
                score += values[i]
                i += 1
            else:
                i += values[i]
        return score

