var calculateScore = function(instructions, values) {
    const n = instructions.length;
    const seen = new Array(n).fill(false);
    let i = 0, score = 0;
    while (i >= 0 && i < n && !seen[i]) {
        seen[i] = true;
        if (instructions[i] === 'add') {
            score += values[i];
            i += 1;
        } else {
            i += values[i];
        }
    }
    return score;
};
